SET CLIENT_ENCODING TO UTF8;
SET STANDARD_CONFORMING_STRINGS TO ON;
BEGIN;
CREATE TABLE "terreno_urbano" (gid serial,
"objectid" float8,
"avaluo_ter" numeric,
"avaluo_com" numeric,
"terreno_co" varchar(30),
"dimension" int4,
"etiqueta" varchar(254),
"relacion_s" int4,
"espacio_de" varchar(254),
"local_id" varchar(254),
"created_us" varchar(254),
"created_da" date,
"last_edite" varchar(254),
"last_edi_1" date,
"globalid" varchar(38),
"shape_leng" numeric,
"shape_area" numeric);
ALTER TABLE "terreno_urbano" ADD PRIMARY KEY (gid);
SELECT AddGeometryColumn('','terreno_urbano','geom','4326','MULTIPOLYGON',2);
CREATE INDEX ON "terreno_urbano" USING GIST ("geom");
COMMIT;
ANALYZE "terreno_urbano";
